      newSubticketLabels.trim().length > 0 ||
      linkSubticketId.length > 0 ||
      title !== ticket.frontMatter.title ||
      priority !== ticket.frontMatter.priority ||

                      markdown: markdownFromSubticketDraft(subticket, draft.title)
                    }))
                  : []
            }
          : {
