            }
      );
      setToast({ kind: "success", message: effectiveTicketType === "epic" ? "Epic created." : "Ticket created." });
      onCreated();
      onClose();
    } catch (error) {
      setToast({ kind: "error", message: error instanceof Error ? error.message : "Unable to create ticket." });
    } finally {
      setSaving(false);
    }
  };

  return (
