+            >
+              {creating ? <Loader2 className="spin" size={16} /> : created ? <Check size={16} /> : <Plus size={16} />}
+              {creating ? "Creating..." : created ? "Created" : "Create"}
+            </button>
+          </article>
+        );
+      })}
+    </div>
+  );
